public void testSeparatorWithPrinterOnly() {
    PeriodFormatter pfmt = new PeriodFormatterBuilder()
        .appendYears()
        .appendSuffix("Y")
        .appendSeparatorIfFieldsAfter("T")
        .appendHours()
        .appendSuffix("H")
        .toPrinter();
    String result = pfmt.print(new Period(1, 0, 0, 0, 2, 0, 0, 0));
    assertTrue(result.contains("Y"));
    assertTrue(result.contains("H"));
}

public void testSeparatorWithParserOnly() {
    PeriodFormatter pfmt = new PeriodFormatterBuilder()
        .appendYears()
        .appendSuffix("Y")
        .appendSeparatorIfFieldsAfter("T")
        .appendHours()
        .appendSuffix("H")
        .toParser();
    Period period = pfmt.parsePeriod("1YT2H");
    assertEquals(1, period.getYears());
    assertEquals(2, period.getHours());
}

public void testMultipleSeparators() {
    PeriodFormatter pfmt = new PeriodFormatterBuilder()
        .appendYears()
        .appendSuffix("Y")
        .appendSeparatorIfFieldsAfter("-")
        .appendMonths()
        .appendSuffix("M")
        .appendSeparatorIfFieldsAfter("T")
        .appendHours()
        .appendSuffix("H")
        .toFormatter();
    Period period = pfmt.parsePeriod("1Y-2MT3H");
    assertEquals(1, period.getYears());
    assertEquals(2, period.getMonths());
    assertEquals(3, period.getHours());
}
